create table dirkspzm32.isi_kostenstellen (
    kst_nr               number(6, 0) not null enable,
    kst_name             varchar2(50 char),
    kst_bemerkung        varchar2(255 char),
    kst_standard_sm_name varchar2(100 char),
    kst_adress_id        number(*, 0),
    created_date         date default sysdate not null enable,
    created_login_id     number(*, 0) default - 1 not null enable,
    last_change_date     date,
    last_change_login_id number(*, 0)
);

alter table dirkspzm32.isi_kostenstellen
    add constraint pk_kst_nr primary key ( kst_nr )
        using index enable;


